import{_ as i,o as r,c as t,ag as a}from"./chunks/framework.Dr9kcJF8.js";const p=JSON.parse('{"title":"如何在飞跃手册进行经验分享","description":"","frontmatter":{},"headers":[],"relativePath":"docs/contribute.md","filePath":"docs/contribute.md"}'),o={name:"docs/contribute.md"};function l(c,e,s,n,d,u){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="如何在飞跃手册进行经验分享" tabindex="-1">如何在飞跃手册进行经验分享 <a class="header-anchor" href="#如何在飞跃手册进行经验分享" aria-label="Permalink to &quot;如何在飞跃手册进行经验分享&quot;">​</a></h1><p>转载自<a href="https://sustech-application.com/" target="_blank" rel="noreferrer">南科大飞跃手册</a>,有删改</p><p>感谢你查看这份指南并着手分享你的经验！要进行分享，主要有两个方法：</p><ol><li><strong>对运营团队简单，对您复杂：</strong> 通过 GitHub Pull Request 进行贡献（推荐），具体有两种方式： <ul><li>直接在 GitHub 网页上进行编辑，或者</li><li>Fork 本仓库，clone 到本地，修改，发起 PR（<strong>强烈推荐</strong>）</li></ul></li><li><strong>对运营团队复杂，对您简单：</strong> 直接上传文件。可在网站 GitHub 仓库中新建一个 Issue，并上传你的帖子文件。或直接将文件发送给我们（邮箱：TBD）。建议使用 Markdown（<code>.md</code>）文件，其他文件格式也可。</li></ol><p>建议经验分享作者参看<a href="./publish">帖子发表工作流程</a>，并完成其中的部分甚至全部，以方便稿子提交与发布。</p><h2 id="关于-markdown" tabindex="-1">关于 Markdown <a class="header-anchor" href="#关于-markdown" aria-label="Permalink to &quot;关于 Markdown&quot;">​</a></h2><p>飞跃手册中的页面使用 Markdown 撰写。Markdown 是一个被广泛使用的标记语言（markup language），它允许你使用纯文本来创建带有简单格式的文档，实现样式与内容的分离。如果你暂不熟悉 Markdown，可以参考以下内容：</p><ul><li>飞跃手册其他帖子的<a href="https://github.com/CUHKSZFYSC/cuhkszfysc.github.io/tree/main/docs" target="_blank" rel="noreferrer">源代码</a></li><li>由飞跃手册维护者撰写的经验分享示例（当前暂未保留）</li><li><a href="https://markdown.com.cn/basic-syntax/" target="_blank" rel="noreferrer">Markdown 基本语法</a></li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>请不要被「代码」、「语法」吓倒！Markdown 格式简单明了，可以被迅速掌握，也许你在了解它之后，会有相见恨晚之感，并迫不及待地把它应用到飞跃手册之外的学习、工作中！</p></div><p>除了 Markdown 通行的一些语法外，VitePress 还支持一些「方言」，可以让你的经验分享更多样，具体请查看<a href="https://vitepress.dev/zh/guide/markdown" target="_blank" rel="noreferrer">Markdown 扩展 | VitePress 文档</a>。如果你熟悉 Vue，甚至可以在经验分享中使用一些 Vue 组件，给读者留下更深的印象！详见<a href="https://vitepress.dev/zh/guide/using-vue" target="_blank" rel="noreferrer">在 Markdown 使用 Vue | VitePress 文档</a>。</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>飞跃手册指定使用 <a href="https://primevue.org" target="_blank" rel="noreferrer">PrimeVue</a> 作为组件库。你可以自行撰写一些组件，但除非有迫切的需要，我们不会向网站中添加新的的依赖。同理，如果你需要添加 markdown-it 插件，也请与维护者联系。</p></div><h2 id="在-github-网页上进行编辑" tabindex="-1">在 GitHub 网页上进行编辑 <a class="header-anchor" href="#在-github-网页上进行编辑" aria-label="Permalink to &quot;在 GitHub 网页上进行编辑&quot;">​</a></h2><p>下文假定你已经拥有并且登录了 GitHub 账号。你也可以先<a href="https://github.com/signup" target="_blank" rel="noreferrer">注册账号</a>。</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>GitHub 的用户界面可能在本指南发布后有所变动，请以实际为准。如遇到问题，欢迎在<a href="https://github.com/CUHKSZFYSC/cuhkszfysc.github.io/discussions" target="_blank" rel="noreferrer">讨论区</a>提出。</p></div><ol><li>访问我们的<a href="https://github.com/CUHKSZFYSC/cuhkszfysc.github.io/tree/main/docs/" target="_blank" rel="noreferrer">仓库</a>，并进入你的分享所属的文件夹，如 <code>grad-application/computer-science-and-engineering</code>。</li><li>点击右上角 <code>Add file</code><ul><li>如果要在网页上进行编辑，选择 <code>Create new file</code></li><li>如果你已经在本地撰写好了 Markdown 格式的经验分享，也可以选择 <code>Upload files</code></li></ul></li><li>若选择在网页上进行编辑，请填写内容，文件名应为 <code>[地区]-年级-姓名.md</code>，如 <code>[US]-15-yanxiangyi.md</code>。</li><li>选择 <code>Commit changes</code>。</li><li>在 <code>Commit message</code> 中概括你的更改，你也可以在 <code>Extended description</code> 中进一步描述你的分享。</li><li>点击 <code>Propose changes</code>。</li><li>为 PR 设置标题，例如 <code>post: [US]-15-yanxiangyi</code>。你也可以添加描述，进一步介绍你的分享，或者添加给维护者的消息。</li><li>确保侧边栏中的 <code>Allow edits from maintainers</code> 被勾选。</li><li>点击<code>Create pull request</code>。</li></ol><p>到此，PR 就已经创建完成！维护者将会查看 PR，进行调整，确认无误后将其合并到主分支，网站更新即完成。提交 PR 后，你可以继续在 PR 上进行修改。<a href="https://netlify.com" target="_blank" rel="noreferrer">Netlify</a> 将会在 PR 中自动添加一条评论，你可以通过点击评论中的预览链接查看网页实际效果。</p><h2 id="在本地编辑-通过-git-进行贡献-最推荐" tabindex="-1">在本地编辑，通过 git 进行贡献（最推荐） <a class="header-anchor" href="#在本地编辑-通过-git-进行贡献-最推荐" aria-label="Permalink to &quot;在本地编辑，通过 git 进行贡献（最推荐）&quot;">​</a></h2><p>这一节假定你已经安装了 git 和相关的编辑器等工具，并且对 git 的使用有最基本的了解。如果你对 git 不甚了解，欢迎你联系维护者寻求帮助，在<a href="https://github.com/CUHKSZFYSC/cuhkszfysc.github.io/discussions" target="_blank" rel="noreferrer">讨论区</a>提问，或者参考 <a href="https://git-scm.com/doc" target="_blank" rel="noreferrer">git 文档</a>进行学习。</p><ol><li><a href="https://github.com/CUHKSZFYSC/cuhkszfysc.github.io/fork" target="_blank" rel="noreferrer">Fork</a> 我们的仓库。</li><li><code>clone</code> 你的 fork 到本地。</li><li>创建一个新分支，用于你的修改：<code>git checkout -b post/your-name</code>。</li><li>在本地使用你喜爱的编辑器进行修改。</li><li><code>commit</code> 你的修改</li><li><code>push</code> 分支到你的 remote。</li><li>在 GitHub 上发起一个到 <code>upstream</code> 的 Pull Request（PR）。</li></ol><p>得益于 <a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">VSCode</a> 以及 <a href="https://github.com/apps/desktop" target="_blank" rel="noreferrer">GitHub Desktop</a> 这样的工具，你可以在完全不使用命令行的情况下完成上述操作！</p><div class="tip custom-block"><p class="custom-block-title">为什么我们最推荐在本地编辑，通过 git 进行贡献？</p><ul><li>你将可以使用你喜爱的编辑器来编辑和预览 Markdown 文件。</li><li>你可以更细致地使用 git 来管理历史修改。</li><li>你可以利用 Prettier 等工具来检查代码问题和格式化，这将大大减轻维护者的负担。</li><li>你可以在本地运行网站预览，确保网页效果符合你的期待。</li></ul></div><p>你可以在本地运行网站，实时查看效果：</p><ul><li>安装 <a href="https://bun.sh/" target="_blank" rel="noreferrer">Bun</a></li><li>安装依赖：<code>bun install</code></li><li>启动开发服务器：<code>bun run dev</code></li><li>在浏览器中访问开发服务器</li></ul><h2 id="上传非-markdown-文件-不推荐" tabindex="-1">上传非 Markdown 文件（不推荐） <a class="header-anchor" href="#上传非-markdown-文件-不推荐" aria-label="Permalink to &quot;上传非 Markdown 文件（不推荐）&quot;">​</a></h2><ul><li>撰写经验分享帖子</li><li>在仓库中<a href="https://github.com/CUHKSZFYSC/cuhkszfysc.github.io/issues/new" target="_blank" rel="noreferrer">创建新 Issue</a>，并将你的帖子作为附件上传。</li><li>如果你不希望使用 GitHub，也可以直接将文件发送给一位维护者： <ul><li>TBD</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">为什么不推荐使用非 Markdown 格式进行分享？</p><ul><li>飞跃手册维护者们需要处理大量帖子以及对网站进行升级，维护。尤其是将帖子从其他格式转换为 Markdown 十分耗费时间。撰写 Markdown 文件，通过 GitHub 提交 PR 进行分享，将大大减轻维护者们的负担。</li><li>通过 GitHub 贡献，可以提供更好的编辑体验，你将能够使用 Markdown 语法及其拓展，预览网站效果，确保网页的最终效果符合你的期待，并与社群进行讨论。</li><li>通过 GitHub 贡献，可以让你成为 本项目的 GitHub contributors 之一，你的头像和用户名将会出现在贡献者列表中。</li><li>通过 GitHub 贡献，可以让你体验开源项目的工作流程，了解 git 的使用，也是一份有趣的经历！</li></ul></div><h2 id="经验分享之外" tabindex="-1">经验分享之外 <a class="header-anchor" href="#经验分享之外" aria-label="Permalink to &quot;经验分享之外&quot;">​</a></h2><p>如果你对建设飞跃手册感兴趣，欢迎联系 <a href="mailto:dancewithdiantong@gmail.com" target="_blank" rel="noreferrer">dancewithdiantong@gmail.com</a> 加入维护团队！</p>',28)])])}const b=i(o,[["render",l]]);export{p as __pageData,b as default};
